package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class GsonBuilderTest {

  private GsonBuilder gsonBuilder;

  @BeforeEach
  void setUp() {
    gsonBuilder = new GsonBuilder();
  }

  @Test
  void testSetLongSerializationPolicy_withValidPolicy_shouldSetFieldAndReturnThis() throws Exception {
    LongSerializationPolicy policy = LongSerializationPolicy.STRING;

    GsonBuilder returned = gsonBuilder.setLongSerializationPolicy(policy);

    assertSame(gsonBuilder, returned);

    // Use reflection to verify private field
    Field field = GsonBuilder.class.getDeclaredField("longSerializationPolicy");
    field.setAccessible(true);
    Object fieldValue = field.get(gsonBuilder);

    assertSame(policy, fieldValue);
  }

  @Test
  void testSetLongSerializationPolicy_withNull_shouldThrowNullPointerException() {
    assertThrows(NullPointerException.class, () -> gsonBuilder.setLongSerializationPolicy(null));
  }
}
